import { useLocation, useNavigate } from "react-router-dom";
import { useState } from "react";
import "./styles/Books.css";

function LibrarianBooks() {
  const navigate = useNavigate();
  const location = useLocation();
  const genre = location.state?.genre || "Literature";

  const [books, setBooks] = useState([
    { title: "Hamlet", author: "William Shakespeare", cover: "https://covers.openlibrary.org/b/isbn/9780743477123-L.jpg" },
    { title: "Macbeth", author: "William Shakespeare", cover: "https://covers.openlibrary.org/b/isbn/9780743477109-L.jpg" }
  ]);

  const [showForm, setShowForm] = useState(false);
  const [newBook, setNewBook] = useState({
    title: "",
    author: "",
    cover: ""
  });

  const addBook = () => {
    if (!newBook.title || !newBook.author || !newBook.cover) {
      alert("Fill all fields");
      return;
    }

    setBooks([...books, newBook]);
    setNewBook({ title: "", author: "", cover: "" });
    setShowForm(false);
  };

  return (
    <div className="books-page">
      <h1 className="books-title">Manage {genre} Books</h1>

      <button className="main-cta" onClick={() => setShowForm(!showForm)}>
        ➕ Add New Book
      </button>

      {showForm && (
        <div className="detail-card">
          <input
            placeholder="Book Title"
            value={newBook.title}
            onChange={(e) => setNewBook({ ...newBook, title: e.target.value })}
          />
          <input
            placeholder="Author"
            value={newBook.author}
            onChange={(e) => setNewBook({ ...newBook, author: e.target.value })}
          />
          <input
            placeholder="Cover Image URL"
            value={newBook.cover}
            onChange={(e) => setNewBook({ ...newBook, cover: e.target.value })}
          />

          <button className="main-cta" onClick={addBook}>
            Save Book
          </button>
        </div>
      )}

      <div className="books-grid">
        {books.map((book, i) => (
          <div key={i} className="book-card">
            <img src={book.cover} alt={book.title} />
            <h3>{book.title}</h3>
            <p>{book.author}</p>
            <span className="card-status avail">Managed</span>
          </div>
        ))}
      </div>

      <button className="back-btn" onClick={() => navigate(-1)}>
        ← Back
      </button>
    </div>
  );
}

export default LibrarianBooks;
